/**
 * Extracts a bearer token from an Authorization header value.
 *
 * @param headerValue - Header value such as `Bearer eyJ...`.
 * @returns The token without the `Bearer` prefix, or `null` when the header is missing or malformed.
 */
export function getBearerToken(headerValue: unknown): string | null {
  if (!headerValue) {
    return null;
  }

  const raw = String(headerValue).trim();
  const match = /^Bearer\s+(.+)$/.exec(raw);
  return match ? match[1] : null;
}
